prompt PL/SQL Developer import file
prompt Created on 2020年8月23日 by wuzheng
set feedback off
set define off
prompt Creating MC_ORGA_PARA...
drop table MC_ORGA_PARA cascade constraints;
prompt Creating MC_ORGA_PARA...
create table MC_ORGA_PARA
(
  org_no        VARCHAR2(30),
  org_name      VARCHAR2(200),
  super_org_id  VARCHAR2(30),
  org_level     VARCHAR2(30),
  org_area      VARCHAR2(30),
  org_level_bu  VARCHAR2(30),
  remark        VARCHAR2(200),
  etl_dt        DATE,
  etl_timestamp TIMESTAMP(6)
)
compress
nologging;
comment on table MC_ORGA_PARA
  is '组织机构表';
comment on column MC_ORGA_PARA.org_no
  is '机构编码';
comment on column MC_ORGA_PARA.org_name
  is '机构名称';
comment on column MC_ORGA_PARA.super_org_id
  is '上级机构编码';
comment on column MC_ORGA_PARA.org_level
  is '组织级别';
comment on column MC_ORGA_PARA.org_area
  is '地区分类';
comment on column MC_ORGA_PARA.org_level_bu
  is '组织业务级别';
comment on column MC_ORGA_PARA.remark
  is '备注';
comment on column MC_ORGA_PARA.etl_dt
  is 'ETL处理日期';
comment on column MC_ORGA_PARA.etl_timestamp
  is 'ETL处理时间戳';

